sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
ASK
WHERE {
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty gokg:HillsboroughCountyFL ;
          goo:recordDateTime ?recordDate .
  ?ntl a goo:NTLImage ;
       goo:representsCounty gokg:HillsboroughCountyFL ;
       goo:acquisitionDateTime ?imageDate .
  FILTER (SUBSTR(STR(?recordDate), 1, 10) = SUBSTR(STR(?imageDate), 1, 10))
}
